        first_val, i2 = parse_signed_int(i)
        if first_val is None:
            return None
        result = first_val
        i = i2

        while True:
            i = skip_spaces(i)
            if i >= n:
                break
            if s[i] not in ('+', '-'):
                return None
            op = s[i]
            i += 1

            next_val, i2 = parse_signed_int(i)
            if next_val is None:
                return None
            if op == '+':
